    private static async Task<object> ProcessDatabaseOperation(dynamic data, ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
        var sanitizedConnectionString = SanitizeConnectionString(connectionString);
        
        log.LogInformation($"Database Connection: {sanitizedConnectionString}");
        
        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            log.LogInformation("Database connection established");
            
            string query = "SELECT * FROM Users WHERE UserId = @UserId";
            log.LogInformation($"Executing Query: {query}");
            
            using (SqlCommand command = new SqlCommand(query, connection))
            {
                command.Parameters.AddWithValue("@UserId", data?.userId?.ToString() ?? "unknown");
                
                var sanitizedParams = new Dictionary<string, string>();
                foreach (SqlParameter param in command.Parameters)
                {
                    sanitizedParams[param.ParameterName] = SanitizeParameterValue(param.ParameterName, param.Value?.ToString());
                }
                log.LogInformation($"Query Parameters: {JsonConvert.SerializeObject(sanitizedParams)}");
                
                using (SqlDataReader reader = await command.ExecuteReaderAsync())
                {
                    var results = new List<Dictionary<string, object>>();
                    
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            row[reader.GetName(i)] = reader.GetValue(i);
                        }
                        results.Add(row);
                    }
                    
                    log.LogInformation($"Query returned {results.Count} rows");
                    
                    return new { success = true, data = results };
                }
            }
        }
    }

    private static void LogSanitizedException(Exception ex, ILogger log)
