            log.LogError($"Inner Exception Message: {ex.InnerException.Message}");
            log.LogError($"Inner Exception Stack Trace: {ex.InnerException.StackTrace}");
        }
        
        log.LogError($"Exception Data: {JsonConvert.SerializeObject(ex.Data)}");
        log.LogError($"Exception Source: {ex.Source}");
        log.LogError($"Exception HResult: {ex.HResult}");
    }

    private static bool IsSensitiveHeader(string headerName)
    {
        var sensitiveHeaders = new[] 
        { 
            "authorization", 
            "cookie", 
            "x-api-key", 
            "x-auth-token",
            "authentication",
            "proxy-authorization"
        };
        
        return sensitiveHeaders.Contains(headerName.ToLower());
    }

    private static string SanitizeQueryString(string queryString)
    {
        if (string.IsNullOrEmpty(queryString))
            return queryString;
            
        var sensitiveParams = new[] { "token", "password", "secret", "key", "apikey", "api_key" };
        var parts = queryString.TrimStart('?').Split('&');
        var sanitized = new List<string>();
        
        foreach (var part in parts)
        {
            var keyValue = part.Split('=');
            if (keyValue.Length == 2 && sensitiveParams.Any(s => keyValue[0].ToLower().Contains(s)))
            {
                sanitized.Add($"{keyValue[0]}=[REDACTED]");
            }
            else
            {
                sanitized.Add(part);
            }
        }
        
        return "?" + string.Join("&", sanitized);
    }

    private static string SanitizeJsonData(string jsonData)
    {
        try
        {
            var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(jsonData);
            var sensitiveFields = new[] { "password", "token", "secret", "apikey", "creditcard", "ssn", "authorization" };
            
            foreach (var key in obj.Keys.ToList())
            {
                if (sensitiveFields.Any(s => key.ToLower().Contains(s)))
                {
                    obj[key] = "[REDACTED]";
                }
            }
            
            return JsonConvert.SerializeObject(obj);
        }
        catch
        {
            return "[Unable to sanitize JSON data]";
        }
    }

    private static string SanitizeParameterValue(string paramName, string value)
    {
        var sensitiveParams = new[] { "password", "token", "secret", "key", "creditcard", "ssn" };
        
        if (sensitiveParams.Any(s => paramName.ToLower().Contains(s)))
        {
