        }
        
        return value;
    }

    private static string SanitizeConnectionString(string connectionString)
    {
        if (string.IsNullOrEmpty(connectionString))
            return connectionString;
            
        var builder = new SqlConnectionStringBuilder(connectionString);
        builder.Password = "[REDACTED]";
        builder.UserID = builder.UserID != null ? $"{builder.UserID.Substring(0, Math.Min(3, builder.UserID.Length))}***" : builder.UserID;
        
        return builder.ToString();
    }

    private static string GetSanitizedUserId(HttpRequest req)
    {
        string userId = req.Headers["X-User-Id"].FirstOrDefault() ?? "anonymous";
        
        if (userId.Length > 10)
        {
            return userId.Substring(0, 10) + "...";
        }
        
        return userId;
    }

    private static string GetClientIp(HttpRequest req)
    {
        string ip = req.Headers["X-Forwarded-For"].FirstOrDefault();
        
        if (string.IsNullOrEmpty(ip))
        {
            ip = req.HttpContext.Connection.RemoteIpAddress?.ToString();
        }
        
        return ip ?? "Unknown";
    }
